// Main search endpoint
app.post('/api/search', async (req, res) => {
  try {
    // Validate input
    const { error, value: searchParams } = searchParamsSchema.validate(req.body, {
      abortEarly: false,
      allowUnknown: false,
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map((d) => d.message),
      });
    }

    // Build the query DSL
    const queryDSL = buildQueryDSL(searchParams);

    console.log('Executing query on index:', searchParams.index);
    console.log('Query DSL:', JSON.stringify(queryDSL, null, 2));

    // Execute the search
    const result = await esClient.search({
      index: searchParams.index,
      body: queryDSL,
    });

    // Format response
    const response = {
      took: result.took,
      timed_out: result.timed_out,
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map((hit) => ({
        _index: hit._index,
        _id: hit._id,
        _score: hit._score,
        _source: hit._source,
        highlight: hit.highlight || undefined,
        sort: hit.sort || undefined,
        inner_hits: hit.inner_hits || undefined,
        fields: hit.fields || undefined,
      })),
    };

    if (result.aggregations) {
      response.aggregations = result.aggregations;
    }

    if (result.suggest) {
      response.suggest = result.suggest;
    }

    res.json(response);
  } catch (err) {
    console.error('Search error:', err);

    if (err.message && err.message.includes('disallowed pattern')) {
      return res.status(400).json({
        error: 'Script validation error',
        message: err.message,
      });
    }

    if (err.meta && err.meta.body) {
      return res.status(err.meta.statusCode || 500).json({
        error: 'Elasticsearch error',
        message: err.meta.body.error?.reason || err.message,
        details: err.meta.body.error,
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

