// Validate script endpoint
app.post('/api/search/validate-script', (req, res) => {
  try {
    const { script, params } = req.body;

    if (!script) {
      return res.status(400).json({
        valid: false,
        error: 'Script is required',
      });
    }

    const validatedScript = validateScript(script);

    res.json({
      valid: true,
      sanitized_script: validatedScript,
      params: params || {},
    });
  } catch (err) {
    res.status(400).json({
      valid: false,
      error: err.message,
    });
  }
});

// Multi-search endpoint
app.post('/api/msearch', async (req, res) => {
  try {
    const { searches } = req.body;

    if (!Array.isArray(searches) || searches.length === 0) {
      return res.status(400).json({
        error: 'searches must be a non-empty array',
      });
    }

    if (searches.length > 20) {
      return res.status(400).json({
        error: 'Maximum 20 searches allowed per multi-search request',
      });
    }

    const bulkBody = [];

    for (const search of searches) {
      const { error, value: searchParams } = searchParamsSchema.validate(search, {
        abortEarly: false,
        allowUnknown: false,
      });

      if (error) {
        return res.status(400).json({
          error: 'Validation error in one of the searches',
          details: error.details.map((d) => d.message),
        });
      }

      const queryDSL = buildQueryDSL(searchParams);
      bulkBody.push({ index: searchParams.index });
      bulkBody.push(queryDSL);
    }

    const result = await esClient.msearch({ body: bulkBody });

    const responses = result.responses.map((response) => {
      if (response.error) {
        return {
          error: response.error,
        };
      }

      return {
        took: response.took,
        timed_out: response.timed_out,
        total: response.hits.total,
        max_score: response.hits.max_score,
        hits: response.hits.hits.map((hit) => ({
          _index: hit._index,
          _id: hit._id,
          _score: hit._score,
          _source: hit._source,
          highlight: hit.highlight || undefined,
        })),
        aggregations: response.aggregations || undefined,
        suggest: response.suggest || undefined,
      };
    });

    res.json({ took: result.took, responses });
  } catch (err) {
    console.error('Multi-search error:', err);
    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

// Scoring templates - predefined scoring configurations
const SCORING_TEMPLATES = {
  recency_boost: {
    description: 'Boosts more recent documents using a decay function on a date field',
    script: "double decay = Math.exp(-params.decay_rate * ((double)(new Date().getTime() - doc[params.date_field].value.toInstant().toEpochMilli()) / 86400000)); return _score * (1 + params.boost_factor * decay);",
    default_params: {
      date_field: 'created_at',
      decay_rate: 0.05,
      boost_factor: 2.0,
    },
  },
  popularity_boost: {
    description: 'Boosts documents by a popularity/count field using log scaling',
    script: "double popularity = doc[params.popularity_field].size() > 0 ? doc[params.popularity_field].value : 0; return _score * (1 + params.boost_factor * Math.log(1 + popularity));",
    default_params: {
      popularity_field: 'view_count',
      boost_factor: 1.5,
    },
  },
  field_value_factor: {
    description: 'Multiplies score by a field value with saturation',
    script: "double fieldVal = doc[params.field].size() > 0 ? doc[params.field].value : params.missing_value; double factor = params.modifier == 'log1p' ? Math.log(1 + fieldVal) : (params.modifier == 'sqrt' ? Math.sqrt(fieldVal) : fieldVal); return _score * (1 + params.weight * factor);",
    default_params: {
      field: 'relevance_score',
      missing_value: 0,
      modifier: 'log1p',
      weight: 1.0,
    },
  },
  freshness_with_quality: {
    description: 'Combines recency decay with a quality/rating factor',
    script: "double rating = doc[params.quality_field].size() > 0 ? doc[params.quality_field].value : params.default_quality; double daysSince = (double)(new Date().getTime() - doc[params.date_field].value.toInstant().toEpochMilli()) / 86400000; double freshness = 1.0 / (1.0 + params.time_decay * daysSince); return _score * (params.quality_weight * rating + params.freshness_weight * freshness);",
    default_params: {
      quality_field: 'rating',
      date_field: 'published_at',
      default_quality: 3.0,
      time_decay: 0.01,
      quality_weight: 0.6,
      freshness_weight: 0.4,
    },
  },
  geo_distance_decay: {
    description: 'Boosts results closer to a given geo point',
    script: "double lat = doc[params.geo_field].size() > 0 ? doc[params.geo_field].lat : 0; double lon = doc[params.geo_field].size() > 0 ? doc[params.geo_field].lon : 0; double dist = Math.sqrt(Math.pow(lat - params.origin_lat, 2) + Math.pow(lon - params.origin_lon, 2)); return _score * Math.exp(-params.decay_rate * dist);",
    default_params: {
      geo_field: 'location',
      origin_lat: 0.0,
      origin_lon: 0.0,
      decay_rate: 0.1,
    },
  },
};

