// Get a specific scoring template with full details
app.get('/api/scoring-templates/:name', (req, res) => {
  const template = SCORING_TEMPLATES[req.params.name];
  if (!template) {
    return res.status(404).json({
      error: `Scoring template '${req.params.name}' not found`,
      available: Object.keys(SCORING_TEMPLATES),
    });
  }
  res.json({ name: req.params.name, ...template });
});

// Search with a scoring template
app.post('/api/search/with-template/:templateName', async (req, res) => {
  try {
    const template = SCORING_TEMPLATES[req.params.templateName];
    if (!template) {
      return res.status(404).json({
        error: `Scoring template '${req.params.templateName}' not found`,
        available: Object.keys(SCORING_TEMPLATES),
      });
    }

    // Merge template scoring into the request
    const searchBody = {
      ...req.body,
      scoring: {
        script: template.script,
        params: {
          ...template.default_params,
          ...(req.body.scoring_params || {}),
        },
        boost_mode: req.body.boost_mode || 'replace',
      },
    };

    // Remove the scoring_params helper field
    delete searchBody.scoring_params;
    delete searchBody.boost_mode;

    const { error, value: searchParams } = searchParamsSchema.validate(searchBody, {
      abortEarly: false,
      allowUnknown: false,
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map((d) => d.message),
      });
    }

    const queryDSL = buildQueryDSL(searchParams);

    console.log('Executing templated search on index:', searchParams.index);
    console.log('Template:', req.params.templateName);
    console.log('Query DSL:', JSON.stringify(queryDSL, null, 2));

    const result = await esClient.search({
      index: searchParams.index,
      body: queryDSL,
    });

    const response = {
      template_used: req.params.templateName,
      took: result.took,
      timed_out: result.timed_out,
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map((hit) => ({
        _index: hit._index,
        _id: hit._id,
        _score: hit._score,
        _source: hit._source,
        highlight: hit.highlight || undefined,
      })),
      aggregations: result.aggregations || undefined,
    };

    res.json(response);
  } catch (err) {
    console.error('Template search error:', err);

    if (err.message && err.message.includes('disallowed pattern')) {
      return res.status(400).json({
        error: 'Script validation error',
        message: err.message,
      });
    }

    if (err.meta && err.meta.body) {
      return res.status(err.meta.statusCode || 500).json({
        error: 'Elasticsearch error',
        message: err.meta.body.error?.reason || err.message,
        details: err.meta.body.error,
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

// Index info endpoint
app.get('/api/indices/:index', async (req, res) => {
  try {
    const indexName = req.params.index;

    if (!/^[a-z0-9_\-.*]+$/.test(indexName)) {
      return res.status(400).json({ error: 'Invalid index name' });
    }

    const [mapping, settings, stats] = await Promise.all([
      esClient.indices.getMapping({ index: indexName }),
      esClient.indices.getSettings({ index: indexName }),
      esClient.indices.stats({ index: indexName }),
    ]);

    res.json({
      mapping,
      settings,
      stats: {
        docs: stats._all.primaries.docs,
        store: stats._all.primaries.store,
      },
    });
  } catch (err) {
    console.error('Index info error:', err);
    res.status(err.meta?.statusCode || 500).json({
      error: err.message,
    });
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({
    error: 'Internal server error',
    message: process.env.NODE_ENV === 'development' ? err.message : 'An unexpected error occurred',
  });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Enterprise Search Platform running on port ${PORT}`);
  console.log(`Elasticsearch node: ${process.env.ELASTICSEARCH_URL || 'http://localhost:9200'}`);
});

module.exports = {
  app,
  buildQueryDSL,
  validateScript,
  buildFilterClause,
  buildAggregation,
  SCORING_TEMPLATES,
};